import { listInstances, fleetStats } from "@/lib/queries";
import BulkActionBar from "./BulkActionBar";

export const dynamic = "force-dynamic";

function pct(n: number, total: number) {
  if (!total) return 0;
  return Math.round((n / total) * 100);
}

const OS_COLORS: Record<string, string> = {
  Ubuntu: "#e95420",
  Debian: "#a80030",
  Fedora: "#294172",
  CentOS: "#932279",
  "Red Hat Enterprise Linux": "#cc0000",
  "Rocky Linux": "#10b981",
  AlmaLinux: "#0d597f",
  Arch: "#1793d1",
  "openSUSE Leap": "#73ba25",
  Linux: "#6b7689",
};

export default async function Page() {
  const [instances, stats] = await Promise.all([listInstances(), fleetStats()]);

  // Widgets
  const osCounts = new Map<string, number>();
  for (const i of instances) {
    const k = i.osName ?? "Unknown";
    osCounts.set(k, (osCounts.get(k) ?? 0) + 1);
  }
  const osRows = [...osCounts.entries()].sort((a, b) => b[1] - a[1]);

  const compliant = instances.filter((i) => i.updatesAvailable === 0 && i.lastSeen).length;
  const pending = instances.filter((i) => i.updatesAvailable > 0 && i.securityUpdates === 0).length;
  const critical = instances.filter((i) => i.securityUpdates > 0).length;
  const unknown = instances.length - compliant - pending - critical;
  const patchRows = [
    { label: "Up to date", n: compliant, color: "var(--green)" },
    { label: "Updates pending", n: pending, color: "var(--amber)" },
    { label: "Security updates", n: critical, color: "var(--red)" },
    { label: "Unknown", n: unknown, color: "var(--muted-2)" },
  ];

  return (
    <>
      <h1>Dashboard</h1>
      <p className="subtitle">
        Fleet health, patch compliance, and recent activity across your managed Linux endpoints.
      </p>

      <div className="kpi-grid">
        <div className="kpi">
          <div className="icon-tile blue">▢</div>
          <div>
            <div className="num">{stats.total}</div>
            <div className="lbl">Endpoints</div>
          </div>
        </div>
        <div className="kpi">
          <div className="icon-tile green">●</div>
          <div>
            <div className="num">{stats.online}</div>
            <div className="lbl">Online now</div>
          </div>
        </div>
        <div className="kpi">
          <div className="icon-tile amber">↑</div>
          <div>
            <div className="num">{stats.needUpdates}</div>
            <div className="lbl">Updates pending</div>
          </div>
        </div>
        <div className="kpi">
          <div className="icon-tile red">!</div>
          <div>
            <div className="num">{stats.needSecurity}</div>
            <div className="lbl">Security critical</div>
          </div>
        </div>
      </div>

      <div className="widgets">
        <div className="card">
          <div className="card-header"><h3>Patch compliance</h3>
            <span className="muted" style={{ fontSize: 12 }}>
              {pct(compliant, instances.length)}% compliant
            </span>
          </div>
          <div className="card-pad">
            {instances.length === 0 ? (
              <div className="muted" style={{ fontSize: 13 }}>No data yet.</div>
            ) : (
              patchRows.map((r) => (
                <div key={r.label} className="bar-row">
                  <span className="lbl-l">{r.label}</span>
                  <div className="bar">
                    <div
                      style={{
                        width: `${pct(r.n, instances.length)}%`,
                        background: r.color,
                      }}
                    />
                  </div>
                  <span className="lbl-r">{r.n}</span>
                </div>
              ))
            )}
          </div>
        </div>

        <div className="card">
          <div className="card-header"><h3>OS distribution</h3>
            <span className="muted" style={{ fontSize: 12 }}>{osRows.length} distros</span>
          </div>
          <div className="card-pad">
            {osRows.length === 0 ? (
              <div className="muted" style={{ fontSize: 13 }}>No data yet.</div>
            ) : (
              osRows.map(([os, n]) => (
                <div key={os} className="bar-row">
                  <span className="lbl-l">{os}</span>
                  <div className="bar">
                    <div
                      style={{
                        width: `${pct(n, instances.length)}%`,
                        background: OS_COLORS[os] ?? "var(--accent)",
                      }}
                    />
                  </div>
                  <span className="lbl-r">{n}</span>
                </div>
              ))
            )}
          </div>
        </div>
      </div>

      <h2>Endpoints</h2>
      <div className="card" style={{ padding: 0, overflow: "hidden" }}>
        <BulkActionBar instances={instances} />
      </div>
    </>
  );
}
